-- Script pour générer des données de test pour customerbills et billlines
-- Génère 100 customerbills avec partyRef=2 et billcycle_id=1
-- Chaque customerbill a entre 1 et 10 billlines associées

USE customerbills;

-- Désactiver temporairement les vérifications de clés étrangères pour accélérer l'insertion
SET FOREIGN_KEY_CHECKS = 0;

-- Générer 100 customerbills

-- Générer des billlines pour chaque customerbill (entre 1 et 10 par customerbill)
DELIMITER //
CREATE PROCEDURE generate_billlines()
BEGIN
    DECLARE i INT DEFAULT 1;
    DECLARE num_lines INT;
    DECLARE bill_id INT;

    WHILE i <= 100 DO
        -- Générer entre 1 et 10 lignes par facture
        SET num_lines = FLOOR(1 + RAND() * 10);
        SET bill_id = i;

        WHILE num_lines > 0 DO
             CONCAT('USG-', FLOOR(1000 + RAND() * 9000)),
             ROUND(RAND() * 100, 2));
            SET num_lines = num_lines - 1;
        END WHILE;

        SET i = i + 1;
    END WHILE;
END //
DELIMITER ;

-- Exécuter la procédure pour générer les billlines
CALL generate_billlines();

-- Supprimer la procédure après utilisation
DROP PROCEDURE IF EXISTS generate_billlines;

-- Réactiver les vérifications de clés étrangères
SET FOREIGN_KEY_CHECKS = 1;

-- Afficher un résumé
SELECT 'customerbills' AS table_name, COUNT(*) AS row_count FROM customerbills
UNION ALL
SELECT 'billlines' AS table_name, COUNT(*) AS row_count FROM billlines;